// Generate MD5 signature for balance check
const crypto = require('crypto');
const username = '{{DIGIFLAZZ_USERNAME}}';
const apiKey = '{{DIGIFLAZZ_API_KEY}}';
const command = 'depo';

const signature = crypto.createHash('md5').update(username + apiKey + command).digest('hex');

return {
  json: {
    cmd: 'deposit',
    username: username,
    sign: signature
  }
};

// Handle both success and error responses for balance check
const response = $input.first();

if (response.json && response.json.data) {
  // Success response
  const data = response.json.data;
  const balance = Number(data.deposit || 0);

  let statusIcon = '';
  let statusColor = '';
  let warningText = '';

  if (balance < 100000) {
    statusIcon = '🔴';
    statusColor = 'Need Deposit';
    warningText = '⚠️ *Warning:* Your balance is low! Please make a deposit soon.';
  } else if (balance < 500000) {
    statusIcon = '🟡';
    statusColor = 'Good';
    warningText = '✅ Your balance is sufficient for transactions.';
  } else {
    statusIcon = '🟢';
    statusColor = 'Very Good';
    warningText = '✅ Your balance is sufficient for transactions.';
  }

  const message = `💰 *Balance Information*\n\n💳 Deposit Balance: *Rp ${balance.toLocaleString('id-ID')}*\n\n${warningText}\n\n📊 Status: ${statusIcon} ${statusColor}\n\n⏰ Checked at: ${new Date().toLocaleString('en-US', { timeZone: 'Asia/Jakarta' })} WIB`;

  return {
    json: {
      success: true,
      message: message,
      balance: balance,
      status: statusColor
    }
  };
} else {
  // Error response
  let errorMessage = '❌ *Failed to Check Balance*\n\n';

  if (response.json && response.json.data && response.json.data.rc) {
    const rc = response.json.data.rc;
    const msg = response.json.data.message || 'Unknown error';
    errorMessage += `📋 Response Code: ${rc}\n💬 Message: ${msg}\n\n`;

    switch (rc) {
      case '41':
        errorMessage += '💡 Solution: Invalid signature, check API Key';
        break;
      case '45':
        errorMessage += '💡 Solution: IP not recognized, contact admin';
        break;
      default:
        errorMessage += '💡 Contact customer service for assistance';
    }
  } else {
    errorMessage += '🔍 Network error occurred\n💡 Please try again in a few moments';
  }

  return {
    json: {
      success: false,
      message: errorMessage
    }
  };
}

