// Generate MD5 signature for transaction history
const crypto = require('crypto');
const username = '{{DIGIFLAZZ_USERNAME}}';
const apiKey = '{{DIGIFLAZZ_API_KEY}}';
const command = 'history';

const signature = crypto.createHash('md5').update(username + apiKey + command).digest('hex');

return {
  json: {
    cmd: 'history',
    username: username,
    sign: signature,
    start_date: new Date(Date.now() - 7*24*60*60*1000).toISOString().split('T')[0], // 7 days ago
    end_date: new Date().toISOString().split('T')[0] // today
  }
};

